import{_ as a,o as i,c as t,a2 as r}from"./chunks/framework.Dj2sMFyx.js";const h=JSON.parse('{"title":"API Stability","description":"","frontmatter":{},"headers":[],"relativePath":"reference/api-stability.md","filePath":"reference/api-stability.md","lastUpdated":1784914006000}'),o={name:"reference/api-stability.md"};function l(s,e,n,c,d,p){return i(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="api-stability" tabindex="-1">API Stability <a class="header-anchor" href="#api-stability" aria-label="Permalink to &quot;API Stability&quot;">​</a></h1><p>Kandelo is still moving quickly. Assume browser-facing APIs can change at any time unless a future release explicitly marks them stable.</p><p>This applies to:</p><ul><li><code>BrowserKernel</code> constructor and boot options;</li><li>browser worker entry packaging;</li><li>package export paths;</li><li>VFS image metadata;</li><li><code>/etc/kandelo/demo.json</code>;</li><li>gallery manifest fields;</li><li>package-source workflow inputs;</li><li>release index details;</li><li>boot URL query parameters and share URL fragments.</li></ul><h2 id="integration-guidance" tabindex="-1">Integration Guidance <a class="header-anchor" href="#integration-guidance" aria-label="Permalink to &quot;Integration Guidance&quot;">​</a></h2><p>For production or long-lived demos:</p><ul><li>pin the Kandelo commit or npm package version;</li><li>store the Kandelo ABI version used to build each image;</li><li>rebuild VFS images after ABI or package-tooling changes;</li><li>test boot in the browser UI after every Kandelo upgrade;</li><li>treat direct source imports such as <code>@host/browser-kernel-host</code> as private-to-source-checkout usage;</li><li>watch the repository docs and release notes before updating.</li></ul><h2 id="what-is-more-stable" tabindex="-1">What Is More Stable <a class="header-anchor" href="#what-is-more-stable" aria-label="Permalink to &quot;What Is More Stable&quot;">​</a></h2><p>These ideas are core to Kandelo, but individual APIs may still change:</p><ul><li>browser execution requires cross-origin isolation;</li><li>the kernel runs in a dedicated worker;</li><li>browser machines boot from VFS images;</li><li>package-source repositories publish ABI-scoped artifacts;</li><li>the browser gallery shows entries only when matching artifacts are available.</li></ul><p>When in doubt, prefer direct VFS image links for simple sharing and package-source repositories for repeatable distribution.</p>',11)])])}const b=a(o,[["render",l]]);export{h as __pageData,b as default};
